<template>
<div id = "wrap">
    <div id = "section">
        <h1 id="title"/>
        <p id="date"/>
        <p id="updatedDate"/>
        <p id="tags"/>
        <hr/>
    </div>
    <div id = "text"/>
</div>
</template>

<script>

export default {
    name: 'Post',

    blogpostData: null,
    blogpostTxt: null,
    
    created(){
        try{
            const title = this.$route.params.title;
            const showdown = require('showdown');
            const converter = new showdown.Converter({tables: true});
            

            this.blogpostTxt = converter.makeHtml(require(`raw-loader!./Posts/${title}.md`).default);            
            this.blogpostData = require(`./Posts/${title}.json`);
        }
        catch(err){
            console.log(err);
        }
    },
    mounted(){
        //once DOM has been loaded, inject md html
        document.getElementById('text').innerHTML = this.blogpostTxt;
        document.getElementById('title').innerHTML = this.blogpostData.fullTitle;
        document.getElementById('date').innerHTML = 'Posted on: ' + Date(this.blogpostData.publishDate);
        if(this.blogpostData.updatedDate)  document.getElementById('updatedDate').innerHTML = 'Updated on: ' + Date(this.blogpostData.updatedDate);
        
         document.getElementById('tags').innerHTML = 'Tags: ' + this.blogpostData.tags.join(', ');
    }
}
</script>

<style scoped>
    #text{
        width: 70%;
        margin: 0 auto;
        margin-bottom: 5rem;
    }
    #section{
        margin: 0 auto;
        width:70%;
    }
    hr{
        border-color: var(--color-primary);
    }

</style>