<template>
<!-- https://dev.to/ananyaneogi/create-a-dark-light-mode-switch-with-css-variables-34l8 -->
    <label class="theme-toggle mt-2">
        <p id="desc" class="mr-3">{{toggle ? 'Dark' : 'Light'}} mode enabled</p>
        <!-- Checkmark state is binded to toggle var and when clicked, themeToggle func is invoked -->
        <input type="checkbox" id="checkbox" v-model="toggle" @change="themeToggle($event)"/>
    </label>
</template>

<script>
export default {
    Name: "ThemeToggle",
    data: function(){
        return{
            //Store theme state - light = false, dark = true
            toggle: false
        }
    },
    methods:{
        themeToggle: function(event){
            if(event){
                //If toggle is set to true, add dark data theme to body 
                if(this.toggle) document.documentElement.setAttribute('data-theme', 'dark');

                //else, add light data theme to body
                else document.documentElement.setAttribute('data-theme', 'light');

                //Set theme state in local storage
                localStorage.setItem('theme', this.toggle);
            }
        }
    },
    created(){
        //Upon initalization, retrieve theme state from local storage 
        //value gets stored as a string in loclastorage so just compare string
        const currentTheme = localStorage.getItem('theme') ? localStorage.getItem('theme') === 'true' : false;

        //Set toggle var to theme (which also updates checkbox appearance b/c 2 way binding)
        this.toggle = currentTheme;

        //Add dark data theme to body
        document.documentElement.setAttribute('data-theme', currentTheme ? 'dark' : 'light');
    }
}
</script>


<style scoped>
    .theme-toggle{
        font-size: 20px;
    }

    #checkbox{
        width:25px;
        height:25px;
        background: blue
    }

    #desc{
        display: inline;
    }
</style>
